 28→/// Checks if a failure reason indicates a transient network error.
 29→/// Returns true if the failure is likely due to network issues that may be
 30→/// resolved by retrying after a delay.
 31→fn is_network_failure(failure_reason: &Option<String>) -> bool {
 32→    let Some(ref reason) = failure_reason else {
 33→        return false;
 34→    };
 35→
 36→    let reason_lower = reason.to_lowercase();
 37→
 38→    // Common network error patterns
 39→    reason_lower.contains("connection refused")
 40→        || reason_lower.contains("connection timed out")
 41→        || reason_lower.contains("connection timeout")
 42→        || reason_lower.contains("connection reset")
 43→        || reason_lower.contains("connection closed")
 44→        || reason_lower.contains("network unreachable")
 45→        || reason_lower.contains("network is unreachable")
 46→        || reason_lower.contains("host unreachable")
 47→        || reason_lower.contains("no route to host")
 48→        || reason_lower.contains("dns resolution failed")
 49→        || reason_lower.contains("could not resolve host")
 50→        || reason_lower.contains("name resolution failed")
 51→        || reason_lower.contains("temporary failure in name resolution")
 52→        || reason_lower.contains("tls handshake")
 53→        || reason_lower.contains("ssl handshake")
 54→        || reason_lower.contains("certificate verify failed")
 55→        || reason_lower.contains("502 bad gateway")
 56→        || reason_lower.contains("503 service unavailable")
 57→        || reason_lower.contains("504 gateway timeout")
 58→        || reason_lower.contains("socket closed")
 59→        || reason_lower.contains("socket error")
 60→        || reason_lower.contains("broken pipe")
 61→        || reason_lower.contains("unexpected eof")
 62→        || reason_lower.contains("connection aborted")
 63→        || reason_lower.contains("no internet connection")
 64→        || reason_lower.contains("network error")
 65→        || reason_lower.contains("dns error")
 66→        || reason_lower.contains("timed out")
 67→}
