 69→/// Checks if a cloud provider API is reachable via TCP probe.
 70→/// Returns true if a TCP connection can be established within 2 seconds.
 71→/// Local providers (ollama-local) always return true without probing.
 72→async fn provider_reachable(provider: &str) -> bool {
 73→    // Local providers don't need network connectivity
 74→    if provider == "ollama-local" {
 75→        return true;
 76→    }
 77→
 78→    // Map provider names to their API endpoints
 79→    let endpoint = match provider {
 80→        "claude" => "api.anthropic.com:443",
 81→        "codex" | "opencode" => "api.openai.com:443",
 82→        _ => {
 83→            // Unknown provider - assume reachable to avoid blocking
 84→            return true;
 85→        }
 86→    };
 87→
 88→    // Try to establish TCP connection with 2s timeout
 89→    match tokio::time::timeout(Duration::from_secs(2), TcpStream::connect(endpoint)).await {
 90→        Ok(Ok(_)) => true,
 91→        Ok(Err(_)) | Err(_) => false,
 92→    }
 93→}
