 50→fn validate_provider(name: &str, p: &Provider) -> anyhow::Result<()> {
 51→    if name.trim().is_empty() {
 52→        anyhow::bail!("provider name cannot be empty");
 53→    }
 54→    if p.command.trim().is_empty() {
 55→        anyhow::bail!("provider '{}': command/adapter cannot be empty", name);
 56→    }
 57→    Ok(())
 58→}
