 60→fn providers_path(cards_dir: &Path) -> PathBuf {
 61→    cards_dir.join("providers.json")
 62→}
 63→
 64→pub fn read_providers(cards_dir: &Path) -> anyhow::Result<ProvidersFile> {
 65→    let p = providers_path(cards_dir);
 66→    if !p.exists() {
 67→        return Ok(ProvidersFile::default());
 68→    }
 69→    let bytes = fs::read(p)?;
 70→    let pf: ProvidersFile = serde_json::from_slice(&bytes)?;
 71→    for (name, provider) in &pf.providers {
 72→        validate_provider(name, provider)?;
 73→    }
 74→    Ok(pf)
 75→}
 76→
 77→pub fn write_providers(cards_dir: &Path, pf: &ProvidersFile) -> anyhow::Result<()> {
 78→    for (name, provider) in &pf.providers {
 79→        validate_provider(name, provider)?;
 80→    }
 81→    let bytes = serde_json::to_vec_pretty(pf)?;
 82→
 83→    let target = providers_path(cards_dir);
 84→    let tmp = target.with_extension("json.tmp");
 85→
 86→    fs::write(&tmp, &bytes)?;
 87→    fs::rename(&tmp, &target)?;
 88→
 89→    Ok(())
 90→}
