137→pub fn rotate_provider_chain(meta: &mut Meta) {
138→    if meta.provider_chain.len() <= 1 {
139→        return;
140→    }
141→    let first = meta.provider_chain.remove(0);
142→    meta.provider_chain.push(first);
143→}
