    39→#[derive(Clone)]
    40→struct RateLimiter {
    41→    requests: Arc<Mutex<HashMap<String, Vec<Instant>>>>,
    42→    max_requests: usize,
    43→    window: Duration,
    44→}
    45→
    46→impl RateLimiter {
    47→    fn new(max_requests: usize, window: Duration) -> Self {
    48→        Self {
    49→            requests: Arc::new(Mutex::new(HashMap::new())),
    50→            max_requests,
    51→            window,
    52→        }
    53→    }
    54→
    55→    fn check_rate_limit(&self, ip: &str) -> bool {
    56→        let mut requests = self.requests.lock().unwrap();
    57→        let now = Instant::now();
    58→        let cutoff = now - self.window;
    59→
    60→        // Get or create the request history for this IP
    61→        let history = requests.entry(ip.to_string()).or_default();
    62→
    63→        // Remove requests outside the time window
    64→        history.retain(|&timestamp| timestamp > cutoff);
    65→
    66→        // Check if rate limit exceeded
    67→        if history.len() >= self.max_requests {
    68→            return false;
    69→        }
    70→
    71→        // Record this request
    72→        history.push(now);
    73→        true
    74→    }
    75→}
