   146→pub fn select_provider(
   147→    cards_dir: &Path,
   148→    meta: Option<&mut Meta>,
   149→    stage: &str,
   150→) -> anyhow::Result<Option<ProviderSelection>> {
   151→    let pf = read_providers(cards_dir)?;
   152→    let now = Utc::now().timestamp();
   153→
   154→    let avoid_provider = if stage == "qa" {
   155→        meta.as_ref()
   156→            .and_then(|m| m.stages.get("implement"))
   157→            .and_then(|r| r.provider.clone())
   158→    } else {
   159→        None
   160→    };
   161→
   162→    let chain: Vec<String> = match meta {
   163→        Some(m) => {
   164→            if m.provider_chain.is_empty() {
   165→                m.provider_chain = vec!["mock".to_string(), "mock2".to_string()];
   166→            }
   167→            m.provider_chain.clone()
   168→        }
   169→        None => vec!["mock".to_string(), "mock2".to_string()],
   170→    };
   171→
   172→    let mut fallback: Option<ProviderSelection> = None;
   173→    for name in chain {
   174→        let Some(p) = pf.providers.get(&name) else {
   175→            continue;
   176→        };
   177→        if let Some(until) = p.cooldown_until_epoch_s {
   178→            if until > now {
   179→                continue;
   180→            }
   181→        }
   182→
   183→        if let Some(ref avoid) = avoid_provider {
   184→            if &name == avoid {
   185→                if fallback.is_none() {
   186→                    fallback = Some((
   187→                        name,
   188→                        p.command.clone(),
   189→                        p.rate_limit_exit,
   190→                        p.env.clone(),
   191→                        p.model.clone(),
   192→                    ));
   193→                }
   194→                continue;
   195→            }
   196→        }
   197→
   198→        return Ok(Some((
   199→            name,
   200→            p.command.clone(),
   201→            p.rate_limit_exit,
   202→            p.env.clone(),
   203→            p.model.clone(),
   204→        )));
   205→    }
   206→
   207→    Ok(fallback)
   208→}
