   210→pub fn set_provider_cooldown(
   211→    cards_dir: &Path,
   212→    provider: &str,
   213→    cooldown_s: i64,
   214→) -> anyhow::Result<()> {
   215→    let mut pf = read_providers(cards_dir)?;
   216→    let now = Utc::now().timestamp();
   217→    if let Some(p) = pf.providers.get_mut(provider) {
   218→        p.cooldown_until_epoch_s = Some(now + cooldown_s);
   219→    }
   220→    write_providers(cards_dir, &pf)?;
   221→    Ok(())
   222→}
