    67→pub fn read_providers(cards_dir: &Path) -> anyhow::Result<ProvidersFile> {
    68→    let p = providers_path(cards_dir);
    69→    if !p.exists() {
    70→        return Ok(ProvidersFile::default());
    71→    }
    72→    let bytes = fs::read(p)?;
    73→    let pf: ProvidersFile = serde_json::from_slice(&bytes)?;
    74→    for (name, provider) in &pf.providers {
    75→        validate_provider(name, provider)?;
    76→    }
    77→    Ok(pf)
    78→}
    79→
    80→pub fn write_providers(cards_dir: &Path, pf: &ProvidersFile) -> anyhow::Result<()> {
    81→    for (name, provider) in &pf.providers {
    82→        validate_provider(name, provider)?;
    83→    }
    84→    let bytes = serde_json::to_vec_pretty(pf)?;
    85→
    86→    let target = providers_path(cards_dir);
    87→    let tmp = target.with_extension("json.tmp");
    88→
    89→    fs::write(&tmp, &bytes)?;
    90→    fs::rename(&tmp, &target)?;
    91→
    92→    Ok(())
    93→}
