   140→pub fn rotate_provider_chain(meta: &mut Meta) {
   141→    if meta.provider_chain.len() <= 1 {
   142→        return;
   143→    }
   144→    let first = meta.provider_chain.remove(0);
   145→    meta.provider_chain.push(first);
