   212→pub fn set_provider_cooldown(
   213→    cards_dir: &Path,
   214→    provider: &str,
   215→    cooldown_s: i64,
   216→) -> anyhow::Result<()> {
   217→    let mut pf = read_providers(cards_dir)?;
   218→    let now = Utc::now().timestamp();
   219→    if let Some(p) = pf.providers.get_mut(provider) {
   220→        p.cooldown_until_epoch_s = Some(now + cooldown_s);
   221→    }
   222→    write_providers(cards_dir, &pf)?;
   223→    Ok(())
   224→}
