    85→
    86→    let target = providers_path(cards_dir);
    87→    let tmp = target.with_extension("json.tmp");
    88→
    89→    fs::write(&tmp, &bytes)?;
    90→    fs::rename(&tmp, &target)?;
    91→
    92→    Ok(())
