   148→pub fn select_provider(
   149→    cards_dir: &Path,
   150→    meta: Option<&mut Meta>,
   151→    stage: &str,
   152→) -> anyhow::Result<Option<ProviderSelection>> {
   153→    let pf = read_providers(cards_dir)?;
   154→    let now = Utc::now().timestamp();
   155→
   156→    let avoid_provider = if stage == "qa" {
   157→        meta.as_ref()
   158→            .and_then(|m| m.stages.get("implement"))
   159→            .and_then(|r| r.provider.clone())
   160→    } else {
   161→        None
   162→    };
   163→
   164→    let chain: Vec<String> = match meta {
   165→        Some(m) => {
   166→            if m.provider_chain.is_empty() {
   167→                m.provider_chain = vec!["mock".to_string(), "mock2".to_string()];
   168→            }
   169→            m.provider_chain.clone()
   170→        }
   171→        None => vec!["mock".to_string(), "mock2".to_string()],
   172→    };
   173→
   174→    let mut fallback: Option<ProviderSelection> = None;
   175→    for name in chain {
   176→        let Some(p) = pf.providers.get(&name) else {
   177→            continue;
   178→        };
   179→        if let Some(until) = p.cooldown_until_epoch_s {
   180→            if until > now {
   181→                continue;
   182→            }
   183→        }
   184→
   185→        if let Some(ref avoid) = avoid_provider {
   186→            if &name == avoid {
   187→                if fallback.is_none() {
   188→                    fallback = Some((
   189→                        name,
   190→                        p.command.clone(),
   191→                        p.rate_limit_exit,
   192→                        p.env.clone(),
   193→                        p.model.clone(),
   194→                    ));
   195→                }
   196→                continue;
   197→            }
   198→        }
   199→
   200→        return Ok(Some((
   201→            name,
   202→            p.command.clone(),
   203→            p.rate_limit_exit,
   204→            p.env.clone(),
   205→            p.model.clone(),
   206→        )));
   207→    }
   208→
   209→    Ok(fallback)
   210→}
