    68→pub fn read_providers(cards_dir: &Path) -> anyhow::Result<ProvidersFile> {
    69→    let p = providers_path(cards_dir);
    70→    if !p.exists() {
    71→        return Ok(ProvidersFile::default());
    72→    }
    73→    let bytes = fs::read(p)?;
    74→    let pf: ProvidersFile = serde_json::from_slice(&bytes)?;
    75→    for (name, provider) in &pf.providers {
    76→        validate_provider(name, provider)?;
    77→    }
    78→    Ok(pf)
    79→}
