    84→    }
    85→    let bytes = serde_json::to_vec_pretty(pf)?;
    86→
    87→    let target = providers_path(cards_dir);
    88→    let tmp = target.with_extension("json.tmp");
    89→
    90→    fs::write(&tmp, &bytes)?;
    91→    fs::rename(&tmp, &target)?;
