   149→pub fn select_provider(
   150→    cards_dir: &Path,
   151→    meta: Option<&mut Meta>,
   152→    stage: &str,
   153→) -> anyhow::Result<Option<ProviderSelection>> {
   154→    let pf = read_providers(cards_dir)?;
   155→    let now = Utc::now().timestamp();
   156→
   157→    let avoid_provider = if stage == "qa" {
   158→        meta.as_ref()
   159→            .and_then(|m| m.stages.get("implement"))
   160→            .and_then(|r| r.provider.clone())
   161→    } else {
   162→        None
   163→    };
   164→
   165→    let chain: Vec<String> = match meta {
   166→        Some(m) => {
   167→            if m.provider_chain.is_empty() {
   168→                m.provider_chain = vec!["mock".to_string(), "mock2".to_string()];
   169→            }
   170→            m.provider_chain.clone()
   171→        }
   172→        None => vec!["mock".to_string(), "mock2".to_string()],
   173→    };
   174→
   175→    let mut fallback: Option<ProviderSelection> = None;
   176→    for name in chain {
   177→        let Some(p) = pf.providers.get(&name) else {
   178→            continue;
   179→        };
   180→        if let Some(until) = p.cooldown_until_epoch_s {
   181→            if until > now {
   182→                continue;
   183→            }
   184→        }
   185→
   186→        if let Some(ref avoid) = avoid_provider {
   187→            if &name == avoid {
   188→                if fallback.is_none() {
   189→                    fallback = Some((
   190→                        name,
   191→                        p.command.clone(),
   192→                        p.rate_limit_exit,
   193→                        p.env.clone(),
   194→                        p.model.clone(),
   195→                    ));
   196→                }
   197→                continue;
   198→            }
   199→        }
   200→
   201→        return Ok(Some((
   202→            name,
   203→            p.command.clone(),
   204→            p.rate_limit_exit,
   205→            p.env.clone(),
   206→            p.model.clone(),
   207→        )));
   208→    }
   209→
   210→    Ok(fallback)
   211→}
