  9→/// A single history entry stored as one JSONL line.
 10→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
 11→pub struct HistoryEntry {
 12→    /// Unix timestamp in milliseconds.
 13→    pub ts: i64,
 14→    /// Provider short name, e.g. "claude".
 15→    pub provider: String,
 16→    /// Primary usage percentage (0-100), `None` if unavailable.
 17→    pub primary_pct: Option<u8>,
 18→    /// Secondary usage percentage (0-100), `None` if unavailable.
 19→    pub secondary_pct: Option<u8>,
 20→}
 21→
 22→/// Return the default history file path: `~/.bop/provider-history.jsonl`.
 23→pub fn history_path() -> Option<PathBuf> {
 24→    dirs::home_dir().map(|h| h.join(".bop").join("provider-history.jsonl"))
 25→}
 26→
 27→/// Append one JSONL line to the history file at `path`.
 28→///
 29→/// Creates parent directories and the file if they don't exist.
 30→/// Uses `O_APPEND` for atomic appends on POSIX/APFS (<4096 byte lines).
 31→pub fn append_history(path: &Path, snapshot: &ProviderSnapshot) -> anyhow::Result<()> {
 32→    if let Some(parent) = path.parent() {
 33→        fs::create_dir_all(parent)
 34→            .with_context(|| format!("cannot create history dir: {}", parent.display()))?;
 35→    }
 36→
 37→    let entry = HistoryEntry {
 38→        ts: chrono::Utc::now().timestamp_millis(),
 39→        provider: snapshot.provider.clone(),
 40→        primary_pct: snapshot.primary_pct,
 41→        secondary_pct: snapshot.secondary_pct,
 42→    };
 43→
 44→    let mut line =
 45→        serde_json::to_string(&entry).context("failed to serialize history entry")?;
 46→    line.push('\n');
 47→
 48→    let mut file = OpenOptions::new()
 49→        .create(true)
 50→        .append(true)
 51→        .open(path)
 52→        .with_context(|| format!("cannot open history file: {}", path.display()))?;
 53→    file.write_all(line.as_bytes())
 54→        .with_context(|| format!("cannot write history entry: {}", path.display()))?;
 55→
 56→    Ok(())
 57→}
 58→
 59→/// Read the last `n` entries for a given provider from the history file.
 60→///
 61→/// Returns entries in chronological order (oldest first).
 62→/// If the file doesn't exist or is empty, returns an empty vec.
 63→/// Malformed lines are silently skipped.
 64→pub fn read_history(path: &Path, provider: &str, n: usize) -> Vec<HistoryEntry> {
 65→    let file = match fs::File::open(path) {
 66→        Ok(f) => f,
 67→        Err(_) => return Vec::new(),
 68→    };
 69→
 70→    let reader = BufReader::new(file);
 71→    let mut entries: Vec<HistoryEntry> = Vec::new();
 72→
 73→    for line in reader.lines() {
 74→        let line = match line {
 75→            Ok(l) => l,
 76→            Err(_) => continue,
 77→        };
 78→        if line.trim().is_empty() {
 79→            continue;
 80→        }
 81→        let entry: HistoryEntry = match serde_json::from_str(&line) {
 82→            Ok(e) => e,
 83→            Err(_) => continue,
 84→        };
 85→        if entry.provider == provider {
 86→            entries.push(entry);
 87→        }
 88→    }
 89→
 90→    // Keep only the last N entries.
 91→    if entries.len() > n {
 92→        entries.drain(..entries.len() - n);
 93→    }
 94→
 95→    entries
 96→}
